              <td style="padding: 12px 0; color: #10B981; font-size: 16px; font-weight: bold; text-align: right; border-bottom: 1px solid #374151;">$${Math.round(t?.potentialStreamingRevenue?.perEvent*.3).toLocaleString()}</td>
